import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useLeads } from '../../context/LeadsContext';
import { LEAD_SOURCES, cn } from '../../utils/helpers';
import { Spinner } from '../ui';

const INITIAL = {
  name: '', email: '', phone: '', company: '', jobTitle: '',
  message: '', source: 'Website',
};

const FIELDS = [
  { key: 'name', label: 'Full Name', placeholder: 'Arjun Mehta', required: true, type: 'text', col: 1 },
  { key: 'email', label: 'Email Address', placeholder: 'arjun@company.com', required: true, type: 'email', col: 1 },
  { key: 'phone', label: 'Phone Number', placeholder: '+91 98765 43210', required: false, type: 'tel', col: 1 },
  { key: 'company', label: 'Company', placeholder: 'TechCorp India', required: false, type: 'text', col: 1 },
  { key: 'jobTitle', label: 'Job Title', placeholder: 'CTO', required: false, type: 'text', col: 1 },
];

export default function CapturePage() {
  const [form, setForm] = useState(INITIAL);
  const [errors, setErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState(null);
  const { createLead } = useLeads();
  const navigate = useNavigate();

  const set = (key) => (e) => {
    setForm((f) => ({ ...f, [key]: e.target.value }));
    if (errors[key]) setErrors((e) => ({ ...e, [key]: undefined }));
  };

  const validate = () => {
    const errs = {};
    if (!form.name.trim()) errs.name = 'Name is required';
    if (!form.email.trim()) errs.email = 'Email is required';
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) errs.email = 'Invalid email format';
    return errs;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }

    setSubmitting(true);
    try {
      const lead = await createLead(form);
      setSuccess(lead);
      setForm(INITIAL);
    } finally {
      setSubmitting(false);
    }
  };

  if (success) {
    return (
      <div className="p-6 flex items-center justify-center min-h-[70vh] animate-fade-in">
        <div className="card p-10 text-center max-w-md">
          <div className="w-20 h-20 rounded-full bg-success-50 flex items-center justify-center text-4xl mx-auto mb-5">🎉</div>
          <h2 className="text-2xl font-bold text-surface-900 mb-2">Lead Captured!</h2>
          <p className="text-surface-500 mb-2">
            <strong className="text-surface-900">{success.name}</strong> has been added to your pipeline.
          </p>
          {success.score != null && (
            <div className="inline-flex items-center gap-2 bg-brand-50 text-brand-700 px-4 py-2 rounded-xl font-semibold text-sm mb-6">
              AI Score: {success.score}/100
            </div>
          )}
          <div className="flex gap-3 justify-center">
            <button onClick={() => navigate('/leads')} className="btn-primary">View All Leads</button>
            <button onClick={() => setSuccess(null)} className="btn-secondary">Add Another</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 animate-fade-in">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-2xl font-bold text-surface-900">Capture New Lead</h1>
          <p className="text-surface-400 mt-1">Fill in the details below. AI will automatically score this lead on submission.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Main fields */}
          <div className="card p-6 space-y-5">
            <h2 className="text-sm font-semibold text-surface-700 pb-2 border-b border-surface-100">Contact Information</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
              {FIELDS.map(({ key, label, placeholder, required, type }) => (
                <div key={key} className={key === 'name' || key === 'email' ? '' : ''}>
                  <label className="label">
                    {label} {required && <span className="text-danger-500 normal-case tracking-normal">*</span>}
                  </label>
                  <input
                    type={type}
                    value={form[key]}
                    onChange={set(key)}
                    placeholder={placeholder}
                    className={cn('input-field', errors[key] && 'border-danger-300 focus:ring-danger-200 focus:border-danger-400')}
                  />
                  {errors[key] && <p className="text-xs text-danger-500 mt-1">{errors[key]}</p>}
                </div>
              ))}

              {/* Source dropdown */}
              <div>
                <label className="label">Lead Source</label>
                <select value={form.source} onChange={set('source')} className="input-field">
                  {LEAD_SOURCES.map((s) => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
          </div>

          {/* Message */}
          <div className="card p-6">
            <h2 className="text-sm font-semibold text-surface-700 pb-2 border-b border-surface-100 mb-5">Additional Details</h2>
            <div>
              <label className="label">Message / Notes</label>
              <textarea
                value={form.message}
                onChange={set('message')}
                placeholder="Describe the lead's needs, pain points, or any context that will help with outreach…"
                rows={5}
                className="input-field resize-none"
              />
              <p className="text-xs text-surface-400 mt-1.5">More detail = better AI scoring and analysis</p>
            </div>
          </div>

          {/* AI info banner */}
          <div className="rounded-2xl bg-gradient-to-r from-brand-50 to-purple-50 border border-brand-100 p-5 flex gap-4">
            <div className="text-2xl flex-shrink-0">🤖</div>
            <div>
              <p className="text-sm font-semibold text-surface-800">AI-Powered Scoring</p>
              <p className="text-xs text-surface-500 mt-0.5 leading-relaxed">
                This lead will be automatically scored 0–100 based on job title, company, source, and message intent. High-scoring leads (80+) are flagged as hot.
              </p>
            </div>
          </div>

          {/* Submit */}
          <div className="flex items-center justify-between">
            <button
              type="button"
              onClick={() => navigate('/leads')}
              className="btn-ghost"
            >
              ← Cancel
            </button>
            <button
              type="submit"
              disabled={submitting}
              className={cn('btn-primary px-8', submitting && 'opacity-80')}
            >
              {submitting ? (
                <><Spinner size={16} color="white" /> Scoring & Saving…</>
              ) : (
                <>➕ Add Lead</>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
